module priority_encoder(
    input [3:0]         in  ,   

    output reg [1:0]    input_data
);

always@(*)
begin
    if(in[3])       input_data = 2'd3;
    else if(in[2])  input_data = 2'd2;
    else if(in[1])  input_data = 2'd1;
    else if(in[0])  input_data = 2'd0;
    else            input_data = 2'd0;
end

endmodule
